begin; create extension if not exists pgtap with schema extensions; set local search_path=extensions,public; select plan(4); select ok(to_regprocedure('public.accept_merchant_order(uuid,uuid,integer)') is not null,'accept function exists'); select ok(to_regprocedure('public.reject_merchant_order(uuid,uuid,text,uuid,text)') is not null,'reject function exists'); select ok(not has_function_privilege('authenticated','public.accept_merchant_order(uuid,uuid,integer)','EXECUTE'),'direct clients cannot accept'); select ok(not has_function_privilege('authenticated','public.reject_merchant_order(uuid,uuid,text,uuid,text)','EXECUTE'),'direct clients cannot reject'); select * from finish(); rollback;
